161	    private boolean waitCore() {
162	        try {
163	            synchronized (mLock) {
164	                while ((mCondition & COREDUMPED) != COREDUMPED)
165	                    mLock.wait();
166	            }
167	        } catch (InterruptedException e) {
168	            return false;
169	        }
170	        return true;
171	    }
172	
173	    private void notifyCore() {
174	        synchronized (mLock) {
175	            mCondition |= COREDUMPED;
176	            mLock.notifyAll();
177	        }
178	    }
