#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

const inputPath = process.argv[2];
const outputPath = process.argv[3];

if (!inputPath || !outputPath) {
    console.error("Usage: node ua-arch-analyze.js <input.json> <output.json>");
    process.exit(1);
}

const input = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
const { fileNodes, importEdges, allEdges } = input;

// A. Directory Grouping
const dirGroups = {};
const commonPrefix = findCommonPrefix(fileNodes.map(n => n.filePath));

function findCommonPrefix(paths) {
    if (paths.length === 0) return '';
    const segments = paths[0].split('/');
    let prefix = segments[0] + '/';
    for (let i = 1; i < segments.length; i++) {
        const current = segments.slice(0, i + 1).join('/') + '/';
        if (paths.every(p => p.startsWith(current))) {
            prefix = current;
        } else {
            break;
        }
    }
    return prefix;
}

function getDirGroup(filePath) {
    const prefix = commonPrefix;
    if (filePath.startsWith(prefix)) {
        const remainder = filePath.substring(prefix.length);
        const segments = remainder.split('/');
        return segments[0];
    }
    const segments = filePath.split('/');
    return segments[0];
}

fileNodes.forEach(node => {
    const group = getDirGroup(node.filePath);
    if (!dirGroups[group]) dirGroups[group] = [];
    dirGroups[group].push(node.id);
});

// B. Node Type Grouping
const nodeTypeGroups = {};
fileNodes.forEach(node => {
    if (!nodeTypeGroups[node.type]) nodeTypeGroups[node.type] = [];
    nodeTypeGroups[node.type].push(node.id);
});

// C. Import Adjacency Matrix
const fanOut = {};
const fanIn = {};
fileNodes.forEach(n => { fanOut[n.id] = 0; fanIn[n.id] = 0; });

importEdges.forEach(edge => {
    fanOut[edge.source] = (fanOut[edge.source] || 0) + 1;
    fanIn[edge.target] = (fanIn[edge.target] || 0) + 1;
});

// D. Cross-Category Dependency Analysis
const crossCategoryEdges = [];
const nodeTypeSet = new Set(fileNodes.map(n => n.type));

nodeTypeSet.forEach(fromType => {
    nodeTypeSet.forEach(toType => {
        const edges = allEdges.filter(e => {
            const srcNode = fileNodes.find(n => n.id === e.source);
            const tgtNode = fileNodes.find(n => n.id === e.target);
            return srcNode && tgtNode && srcNode.type === fromType && tgtNode.type === toType;
        });
        if (edges.length > 0) {
            crossCategoryEdges.push({ fromType, toType, count: edges.length, edgeType: edges[0].type });
        }
    });
});

// E. Inter-Group Import Frequency
const interGroupImports = [];
const groupPairs = {};

importEdges.forEach(edge => {
    const srcGroup = getDirGroup(fileNodes.find(n => n.id === edge.source)?.filePath || '');
    const tgtGroup = getDirGroup(fileNodes.find(n => n.id === edge.target)?.filePath || '');
    const key = `${srcGroup} -> ${tgtGroup}`;
    if (!groupPairs[key]) groupPairs[key] = 0;
    groupPairs[key]++;
});

Object.keys(groupPairs).forEach(key => {
    const [from, to] = key.split(' -> ');
    interGroupImports.push({ from, to, count: groupPairs[key] });
});

// F. Intra-Group Import Density
const intraGroupDensity = {};
Object.keys(dirGroups).forEach(group => {
    const groupFiles = dirGroups[group];
    let internalEdges = 0;
    let totalEdges = 0;

    importEdges.forEach(edge => {
        const srcInGroup = groupFiles.includes(edge.source);
        const tgtInGroup = groupFiles.includes(edge.target);
        if (srcInGroup || tgtInGroup) totalEdges++;
        if (srcInGroup && tgtInGroup) internalEdges++;
    });

    intraGroupDensity[group] = {
        internalEdges,
        totalEdges,
        density: totalEdges > 0 ? internalEdges / totalEdges : 0
    };
});

// G. Directory Pattern Matching
const patternMap = {
    'java': 'service',
    'cpp': 'service',
    'eajni': 'middleware',
    'opencore': 'core',
    'arm64': 'architecture',
    'arm': 'architecture',
    'lp64': 'architecture',
    'lp32': 'architecture',
    'x86_64': 'architecture',
    'x86': 'architecture',
    'riscv64': 'architecture',
    'app': 'ui',
    'test': 'test',
    'androidTest': 'test',
    'main': 'entry',
    'include': 'middleware'
};

const patternMatches = {};
Object.keys(dirGroups).forEach(group => {
    patternMatches[group] = patternMap[group] || 'service';
});

// H. Deployment Topology Detection
const infraFiles = fileNodes.filter(n =>
    n.name.includes('Dockerfile') ||
    n.name.includes('docker-compose') ||
    n.name.includes('Jenkinsfile') ||
    n.name.includes('.yml') && n.filePath.includes('workflows')
).map(n => n.name);

const deploymentTopology = {
    hasDockerfile: infraFiles.some(f => f.includes('Dockerfile')),
    hasCompose: infraFiles.some(f => f.includes('docker-compose')),
    hasK8s: infraFiles.some(f => f.includes('kubernetes') || f.includes('k8s')),
    hasTerraform: infraFiles.some(f => f.includes('.tf')),
    hasCI: infraFiles.some(f => f.includes('workflows')),
    infraFiles
};

// I. Data Pipeline Detection
const schemaFiles = fileNodes.filter(n =>
    n.filePath.includes('.sql') ||
    n.filePath.includes('.graphql') ||
    n.filePath.includes('.proto') ||
    n.filePath.includes('.prisma')
).map(n => n.filePath);

// J. Documentation Coverage
const groupsWithDocs = Object.keys(dirGroups).filter(g =>
    fileNodes.some(n => getDirGroup(n.filePath) === g && n.type === 'document')
).length;
const totalGroups = Object.keys(dirGroups).length;

const docCoverage = {
    groupsWithDocs,
    totalGroups,
    coverageRatio: totalGroups > 0 ? groupsWithDocs / totalGroups : 0,
    undocumentedGroups: Object.keys(dirGroups).filter(g =>
        !fileNodes.some(n => getDirGroup(n.filePath) === g && n.type === 'document')
    )
};

// K. Dependency Direction
const depDirection = [];
interGroupImports.forEach(ig => {
    const reverse = interGroupImports.find(e => e.from === ig.to && e.to === ig.from);
    if (!reverse || ig.count >= reverse.count) {
        depDirection.push({ dependent: ig.from, dependsOn: ig.to });
    }
});

// File stats
const fileStats = {
    totalFileNodes: fileNodes.length,
    filesPerGroup: Object.fromEntries(Object.entries(dirGroups).map(([k, v]) => [k, v.length])),
    nodeTypeCounts: Object.fromEntries(Object.entries(nodeTypeGroups).map(([k, v]) => [k, v.length]))
};

const output = {
    scriptCompleted: true,
    directoryGroups: dirGroups,
    nodeTypeGroups,
    crossCategoryEdges,
    interGroupImports,
    intraGroupDensity,
    patternMatches,
    deploymentTopology,
    dataPipeline: {
        schemaFiles,
        migrationFiles: [],
        dataModelFiles: [],
        apiHandlerFiles: []
    },
    docCoverage,
    dependencyDirection: depDirection,
    fileStats,
    fileFanIn: fanIn,
    fileFanOut: fanOut
};

fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));
console.log("Architecture analysis completed successfully.");
process.exit(0);

